import express from 'express';
import { MPFacil } from '../src/index.js';

const app = express();
const mp = new MPFacil({
  apiKey: process.env.MP_ACCESS_TOKEN,
  webhookSecret: process.env.MP_WEBHOOK_SECRET
});

app.use(express.json());

mp.on('pago', (dados) => {
  console.log('Pagamento aprovado:', dados.id);
});

mp.on('recusado', (dados) => {
  console.log('Pagamento recusado:', dados.id);
});

mp.on('pendente', (dados) => {
  console.log('Pagamento pendente:', dados.id);
});

mp.on('erro', (erro) => {
  console.error('Erro no webhook:', erro);
});

app.post('/webhook', async (req, res) => {
  const resultado = await mp.processarWebhook({
    body: req.body,
    query: req.query,
    headers: req.headers
  });

  res.status(resultado.ok ? 200 : 400).json(resultado);
});

app.listen(3000, () => {
  console.log('Webhook ouvindo em http://localhost:3000/webhook');
});
